import React, { useState, useMemo } from "react";
import { Table, Card, Button, Space, Typography, Tag, notification, Row, Col, Input, Divider, theme, Modal } from "antd";
import { EditOutlined, PlusOutlined, SearchOutlined, SafetyCertificateOutlined, DeleteOutlined } from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";

import { MOCK_CAMERAS, CameraInfo, LEVEL_MAP } from "../../dashboard/data/mockData";
import DeviceDetailModal from "./components/DeviceDetailModal";

const { Title, Text } = Typography;

export default function DeviceListPage() {
  const { token } = theme.useToken();
  const { t } = useI18n(["management"]);

  const [data, setData] = useState<CameraInfo[]>(MOCK_CAMERAS);
  const [editingDevice, setEditingDevice] = useState<CameraInfo | null>(null);
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [searchText, setSearchText] = useState("");
  const [selectedRowKeys, setSelectedRowKeys] = useState<React.Key[]>([]);

  const handleAdd = () => {
    setEditingDevice(null);
    setIsModalVisible(true);
  };

  const handleEdit = (record: CameraInfo) => {
    setEditingDevice(record);
    setIsModalVisible(true);
  };

  const handleBulkEdit = () => {
    if (selectedRowKeys.length !== 1) return;
    const target = data.find(d => d.id === selectedRowKeys[0]);
    if (target) {
      setEditingDevice(target);
      setIsModalVisible(true);
    }
  };

  const handleBulkDelete = () => {
    Modal.confirm({
      title: t("manager.delete_confirm_title"),
      content: t("manager.delete_confirm_desc", { count: selectedRowKeys.length }),
      okText: t("common.delete"),
      okType: "danger",
      cancelText: t("common.cancel"),
      onOk: () => {
        setData(prev => prev.filter(d => !selectedRowKeys.includes(d.id)));
        setSelectedRowKeys([]);
        notification.success({ message: t("manager.delete_success") });
      }
    });
  };

  const handleSave = (updatedDevice: CameraInfo) => {
    if (editingDevice) {
      // Edit existing
      setData(prev => prev.map(d => d.id === updatedDevice.id ? updatedDevice : d));
    } else {
      // Add new
      const newDevice = {
        ...updatedDevice,
        id: Math.max(...data.map(d => d.id)) + 1, // simple ID generation
        level: 1,
        crowdCount: 0,
        imageUrl: `${import.meta.env.BASE_URL}assets/platforms/crowdsafe/logo_raw.png` // placeholder
      };
      setData(prev => [newDevice as CameraInfo, ...prev]);
    }
    setIsModalVisible(false);
    notification.success({
      message: t("manager.save_success"),
      placement: "topRight"
    });
  };

  const filteredData = useMemo(() => {
    if (!searchText) return data;
    return data.filter(d =>
      d.name.toLowerCase().includes(searchText.toLowerCase()) ||
      d.id.toString().includes(searchText)
    );
  }, [data, searchText]);

  const columns = [
    {
      title: t("manager.device_name"),
      dataIndex: "name",
      key: "name",
      render: (text: string, record: CameraInfo) => (
        <Space>
          <SafetyCertificateOutlined style={{ color: LEVEL_MAP[record.level].color }} />
          <Text strong style={{ color: token.colorText }}>{text}</Text>
        </Space>
      )
    },
    {
      title: t("manager.device_id"),
      dataIndex: "id",
      key: "id",
      render: (id: string) => <Text style={{ color: token.colorTextSecondary }}>{id}</Text>
    },
    {
      title: t("manager.zone_name"),
      dataIndex: "zoneId",
      key: "zoneId",
      render: (zoneId: string) => <Tag color="blue">{zoneId}</Tag>
    },
    {
      title: t("manager.status"),
      dataIndex: "level",
      key: "level",
      render: (level: number) => {
        const lvl = LEVEL_MAP[level as keyof typeof LEVEL_MAP];
        return <Tag color={lvl.color}>{lvl.label}</Tag>;
      }
    },
    {
      title: t("manager.area_count"),
      key: "areas",
      render: (record: CameraInfo) => (
        <Badge count={record.detectionAreas?.length || 0} showZero color={token.colorPrimary} />
      )
    },
    {
      title: t("manager.actions"),
      key: "actions",
      render: (record: CameraInfo) => (
        <Button
          type="text"
          icon={<EditOutlined />}
          style={{ color: token.colorLink }}
          onClick={() => handleEdit(record)}
        />
      )
    }
  ];

  const rowSelection = {
    selectedRowKeys,
    onChange: (keys: React.Key[]) => setSelectedRowKeys(keys),
  };

  return (
    <div style={{ padding: 24, height: "100%", overflowY: "auto", background: token.colorBgLayout }}>
      <Row gutter={[24, 24]}>
        <Col span={24}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 16 }}>
            <div>
              <Title level={2} style={{ color: token.colorText, margin: 0 }}>{t("manager.list_title")}</Title>
              <Text type="secondary" style={{ color: token.colorTextTertiary }}>{t("manager.list_desc")}</Text>
            </div>
            <Space>
              {selectedRowKeys.length > 0 && (
                <Space style={{ marginRight: 16 }}>
                  <Text type="warning" strong>{selectedRowKeys.length} {t("manager.selected_count")}</Text>
                  <Button icon={<EditOutlined />} size="small" onClick={handleBulkEdit} disabled={selectedRowKeys.length !== 1}>{t("manager.bulk_edit")}</Button>
                  <Button danger icon={<DeleteOutlined />} size="small" onClick={handleBulkDelete}>{t("manager.bulk_delete")}</Button>
                  <Divider type="vertical" />
                </Space>
              )}
              <Input
                placeholder={t("manager.search_placeholder")}
                prefix={<SearchOutlined />}
                onChange={e => setSearchText(e.target.value)}
                style={{ width: 250 }}
              />
              <Button type="primary" icon={<PlusOutlined />} style={{ borderRadius: 6 }} onClick={handleAdd}>
                {t("manager.add_device")}
              </Button>
            </Space>
          </div>
        </Col>

        <Col span={24}>
          <Card
            bodyStyle={{ padding: 0 }}
            className="management-card"
            style={{
              borderRadius: 8,
              boxShadow: "0 4px 12px rgba(0,0,0,0.05)",
              border: `1px solid ${token.colorBorderSecondary}`
            }}
          >
            <Table
              rowSelection={rowSelection}
              dataSource={filteredData}
              columns={columns}
              rowKey="id"
              pagination={{ pageSize: 10, showSizeChanger: true }}
              style={{ background: token.colorBgContainer }}
            />
          </Card>
        </Col>
      </Row>

      <DeviceDetailModal
        device={editingDevice}
        visible={isModalVisible}
        onCancel={() => setIsModalVisible(false)}
        onSave={handleSave}
      />
    </div>
  );
}

// Helper Internal Badge (Antd)
function Badge({ count, showZero, color }: any) {
  return (
    <span style={{
      background: color,
      color: "#fff",
      padding: "2px 8px",
      borderRadius: 10,
      fontSize: 11,
      minWidth: 20,
      textAlign: "center",
      display: "inline-block"
    }}>
      {count}
    </span>
  )
}
