import React, { useState } from "react";
import { Modal, Form, Input, Select, Divider, message, Space, Button } from "antd";
import { useI18n } from "@/framework/i18n/hooks";
import { CameraInfo, DetectionArea, MOCK_ZONES } from "../../../dashboard/data/mockData";
import DetectionAreaEditor from "./DetectionAreaEditor";

interface Props {
  device: CameraInfo | null;
  visible: boolean;
  onCancel: () => void;
  onSave: (device: CameraInfo) => void;
}

export default function DeviceDetailModal({ device, visible, onCancel, onSave }: Props) {
  const { t } = useI18n(["management"]);
  const [form] = Form.useForm();
  
  const [areas, setAreas] = useState<DetectionArea[]>(device?.detectionAreas || []);

  React.useEffect(() => {
    if (device) {
      form.setFieldsValue(device);
      setAreas(device.detectionAreas || []);
    } else {
      form.resetFields();
      setAreas([]);
    }
  }, [device, form]);

  const handleSubmit = async () => {
    try {
      const values = await form.validateFields();
      const updatedDevice: CameraInfo = {
        ...device!,
        ...values,
        detectionAreas: areas,
      };
      onSave(updatedDevice);
    } catch (err) {
      // ignore validation errors
    }
  };

  return (
    <Modal
      title={device ? t("manager.edit_device") : t("manager.add_device")}
      open={visible}
      onCancel={onCancel}
      width={900}
      centered
      footer={[
        <Button key="cancel" onClick={onCancel}>{t("manager.cancel")}</Button>,
        <Button key="submit" type="primary" onClick={handleSubmit}>{t("manager.save")}</Button>
      ]}
    >
      <Form form={form} layout="vertical">
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 16 }}>
          <Form.Item name="name" label={t("manager.device_name")} rules={[{ required: true }]}>
            <Input />
          </Form.Item>
          <Form.Item name="id" label={t("manager.device_id")}>
            <Input disabled />
          </Form.Item>
          <Form.Item name="zoneId" label={t("manager.zone_name")}>
            <Select>
              {MOCK_ZONES.map(z => (
                <Select.Option key={z.id} value={z.id}>{z.name}</Select.Option>
              ))}
            </Select>
          </Form.Item>
        </div>
      </Form>
      
      <Divider orientation={"left" as any} style={{ margin: "16px 0 8px 0" }}>{t("manager.detector_area_editor")}</Divider>
      
      {device && (
        <DetectionAreaEditor 
          imageUrl={device.imageUrl} 
          areas={areas} 
          onSave={setAreas} 
        />
      )}
    </Modal>
  );
}
